from semantic_kernel import Kernel
from semantic_kernel.connectors.ai.open_ai import OpenAIChatCompletion

kernel = Kernel()

@kernel.register_function(
    plugin_name="repo_context",
    function_name="get_context"
)
def get_repo_context(repo_url: str, file_pattern: str) -> str:
    """Extract relevant files from repository for analysis"""
    import git
    import os
    repo = git.Repo.clone_from(repo_url, '/tmp/repo')
    files = []
    for root, _, filenames in os.walk('/tmp/repo'):
        for filename in filenames:
            if file_pattern in filename:
                with open(os.path.join(root, filename)) as f:
                    files.append(f.read())
    return "\n".join(files[:10])  # Limit context size

from semantic_kernel import kernel_function

import subprocess
import tempfile
import os

@kernel_function(
    description="Execute Python code in sandbox with timeout",
    name="execute_code"
)
def execute_python(code: str, timeout: int = 30) -> dict:
    with tempfile.TemporaryDirectory() as tmpdir:
        filepath = os.path.join(tmpdir, 'script.py')
        with open(filepath, 'w') as f:
            f.write(code)

        try:
            result = subprocess.run(
                ['python', filepath],
                capture_output=True,
                timeout=timeout,
                text=True
            )
            return {
                'success': result.returncode == 0,
                'stdout': result.stdout,
                'stderr': result.stderr
            }
        except subprocess.TimeoutExpired:
            return {'success': False, 'error': 'Timeout exceeded'}

import { Kernel } from '@semantic-kernel/core';
import { OpenAIChatCompletion } from '@semantic-kernel/connectors-ai-openai';

const kernel = Kernel.create({
  chat: {
    serviceId: 'gpt-4',
    provider: new OpenAIChatCompletion('gpt-4')
  }
});

kernel.importFunctions(
  async function validateTests(code: string, testCode: string) {
    /**
     * Run Jest tests in isolated environment
     * @param {string} code - Generated code
     * @param {string} testCode - Test suite
     * @returns {Promise<{passed: number, failed: number, coverage: number}>}
     */
    const fs = require('fs');
    const path = require('path');
    const { spawn } = require('child_process');

    const tmpDir = '/tmp/jest-test';
    fs.mkdirSync(tmpDir, { recursive: true });

    fs.writeFileSync(path.join(tmpDir, 'code.js'), code);
    fs.writeFileSync(path.join(tmpDir, 'code.test.js'), testCode);

    return new Promise((resolve) => {
      const jest = spawn('npx', ['jest', '--noStackTrace', '--silent'], {
        cwd: tmpDir,
        timeout: 10000
      });

      let output = '';
      jest.stdout.on('data', (data) => output += data);

      jest.on('close', (code) => {
        const passed = output.match(/Tests:\s*(\d+)/)?.[1] || 0;
        resolve({ passed: parseInt(passed), failed: 0, coverage: 0 });
      });
    });
  },
  { name: 'test_validator' }
);

