@kernel.register_function(plugin_name="vex_guardrails", function_name="verify_result")
async def vex_verify_result(function_result: str) -> dict:
    """Vex verification filter for all kernel function results"""

    verification = await vex_client.verify({
        "content": function_result,
        "policy": policy,
        "context": {
            "use_case": "ai_coding_assistant",
            "framework": "semantic_kernel"
        }
    })

    if verification.status == "PASS":
        return {"verified": True, "result": function_result}
    else:
        raise ValueError(f"Vex blocked unsafe output: {verification.issues}")

