        self.vex_client = vex_client

    async def validate_plan(self, plan: str) -> bool:
        verification = await self.vex_client.verify({
            "content": plan,
            "policy": {
                "verifications": ["plan_validity", "plugin_sequence_safety"],
                "risk_profile": "medium"
            },
            "context": {"component": "planner"}
        })
        return verification.status == "PASS"

